-- Tag all new structure_sell PPs with sell-2026; sub-assembly costs with cost-2026
INSERT INTO PRICE_POINT_TAG (price_point_id, tag_id, applied_by_user_id, applied_at)
SELECT pp.id, '11000000-0000-0000-0000-000000000501', pp.set_by_user_id, pp.set_at
FROM PRICE_POINT pp
WHERE pp.scope = 'structure_sell'
  AND pp.id NOT IN (SELECT price_point_id FROM PRICE_POINT_TAG WHERE tag_id = '11000000-0000-0000-0000-000000000501');

INSERT INTO PRICE_POINT_TAG (price_point_id, tag_id, applied_by_user_id, applied_at)
SELECT pp.id, '11000000-0000-0000-0000-000000000401', pp.set_by_user_id, pp.set_at
FROM PRICE_POINT pp
WHERE pp.scope = 'subassembly_cost'
  AND pp.id NOT IN (SELECT price_point_id FROM PRICE_POINT_TAG WHERE tag_id = '11000000-0000-0000-0000-000000000401');

